fn run_external_python_probe(path: &Path) -> Option<PythonVersionProbe> {
    let output = Command::new(path)
    .arg("-c")
    .arg("import json, sys; print(json.dumps({'version': sys.version.split()[0], 'executable': sys.executable}))")
    .stdout(Stdio::piped())
    .stderr(Stdio::null())
    .output()
    .ok()?;

    if !output.status.success() {
        return None;
    }

    serde_json::from_slice::<PythonVersionProbe>(&output.stdout).ok()
}

#[cfg(feature = "backend-python-embed")]
fn run_embedded_python_probe() -> Option<PythonVersionProbe> {
    pyo3::Python::attach(|py| {
        let sys = py.import("sys").ok()?;
        let version: String = sys.getattr("version").ok()?.extract().ok()?;
        let executable: String = sys.getattr("executable").ok()?.extract().ok()?;

        Some(PythonVersionProbe {
            version: version
                .split_whitespace()
                .next()
                .unwrap_or(&version)
                .to_string(),
            executable,
        })
    })
}

#[cfg(not(feature = "backend-python-embed"))]
fn run_embedded_python_probe() -> Option<PythonVersionProbe> {
    None
}

fn repo_path_from_manifest(manifest: Option<&PythonRuntimeManifest>, id: &str) -> Option<String> {
    if let Some(env_key) = repo_env_var(id) {
        if let Some(value) = env_string(env_key) {
            return Some(value);
        }
    }

    manifest
        .and_then(|value| value.repos.as_ref())
        .and_then(|repos| repos.get(id))
        .and_then(|repo| repo.path.clone().or(repo.relative_path.clone()))
}

fn repo_present(path: &Option<String>) -> bool {
    path.as_ref()
        .map(PathBuf::from)
        .map(|value| value.exists())
        .unwrap_or(false)
}

fn support_path_entries(manifest: Option<&PythonRuntimeManifest>) -> BTreeMap<String, String> {
    let mut entries = BTreeMap::new();

    for (key, env_key) in [
        ("mediapipe", MEDIAPIPE_SITE_PACKAGES_ENV),
        ("mplToolkits", MPL_TOOLKITS_SITE_PACKAGES_ENV),
        ("numpy", NUMPY_SITE_PACKAGES_ENV),
        ("numpyCore", NUMPY_CORE_SITE_PACKAGES_ENV),
        ("numpyMatrixlib", NUMPY_MATRIXLIB_SITE_PACKAGES_ENV),
        ("numpyDistutils", NUMPY_DISTUTILS_SITE_PACKAGES_ENV),
        ("proto", PYTHON_PROTO_DIR_ENV),
        ("stdlib", PYTHON_STDLIB_DIR_ENV),
        ("toothGroupNetworkModels", TOOTHGROUPNETWORK_MODELS_ENV),
    ] {
        if let Some(value) = env_string(env_key) {
            entries.insert(key.to_string(), value);
            continue;
        }

        if let Some(value) = manifest
            .and_then(|runtime_manifest| runtime_manifest.support_paths.as_ref())
            .and_then(|support_paths| support_paths.get(key))
            .cloned()
        {
            entries.insert(key.to_string(), value);
        }
    }

    entries
}

