        repo_path_from_manifest(manifest.as_ref(), "slicer-dentalsegmentator");
    let slicer_adt_path =
        repo_path_from_manifest(manifest.as_ref(), "slicer-automated-dental-tools");
    let tooth_group_network_path =
        repo_path_from_manifest(manifest.as_ref(), "tooth-group-network");
